import { GoogleGenAI, Type } from "@google/genai";
import { GroundwaterData, PredictionResult, StressLevel } from "../types";

export const getAIAnalysis = async (data: GroundwaterData): Promise<PredictionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Analyze the groundwater status for the following agricultural data in Tamil Nadu:
    District: ${data.district}
    Annual Rainfall: ${data.rainfall}mm
    Soil Type: ${data.soilType}
    Crop Type: ${data.cropType}
    Borewell Depth: ${data.borewellDepth}m
    Recent Trend: ${data.groundwaterTrend.join(', ')} (annual measurements in meters below ground level)

    Classify the groundwater stress into one of these categories: SAFE, AVERAGE, or DANGER.
    Provide a concise explanation (1-2 lines) of why this status was chosen.

    Return the response in JSON format.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING, enum: ['SAFE', 'AVERAGE', 'DANGER'] },
            explanation: { type: Type.STRING }
          },
          required: ["status", "explanation"]
        }
      }
    });

    const result = JSON.parse(response.text);
    return {
      status: result.status as StressLevel,
      explanation: result.explanation,
      district: data.district,
      cropType: data.cropType
    };
  } catch (error) {
    console.error("AI Analysis failed:", error);
    // Fallback logic
    let status = StressLevel.SAFE;
    if (data.borewellDepth > 100 || data.rainfall < 800) status = StressLevel.DANGER;
    else if (data.borewellDepth > 60 || data.rainfall < 1000) status = StressLevel.AVERAGE;

    return {
      status,
      explanation: "Analysis performed using heuristic model due to connectivity issues. Higher borewell depth and lower rainfall indicate elevated stress levels.",
      district: data.district,
      cropType: data.cropType
    };
  }
};

import React, { useState, useEffect } from 'react';
import { AppScreen, GroundwaterData, PredictionResult, StressLevel } from './types';
import Home from './components/Home';
import DataInput from './components/DataInput';
import Processing from './components/Processing';
import ResultDashboard from './components/ResultDashboard';
import Recommendations from './components/Recommendations';
import About from './components/About';
import { getAIAnalysis } from './services/gemini';
import { Layout } from './components/Layout';

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<AppScreen>(AppScreen.HOME);
  const [inputData, setInputData] = useState<GroundwaterData | null>(null);
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);

  const handleStart = () => setCurrentScreen(AppScreen.DATA_INPUT);
  const handleViewImpact = () => setCurrentScreen(AppScreen.ABOUT);

  const handleDataSubmit = async (data: GroundwaterData) => {
    setInputData(data);
    setCurrentScreen(AppScreen.PROCESSING);

    // Perform AI analysis
    const result = await getAIAnalysis(data);

    // Simulate processing time for UX
    setTimeout(() => {
      setPrediction(result);
      setCurrentScreen(AppScreen.RESULTS);
    }, 2500);
  };

  const reset = () => {
    setInputData(null);
    setPrediction(null);
    setCurrentScreen(AppScreen.HOME);
  };

  const renderScreen = () => {
    switch (currentScreen) {
      case AppScreen.HOME:
        return <Home onStart={handleStart} onViewHow={handleViewImpact} />;
      case AppScreen.DATA_INPUT:
        return <DataInput onSubmit={handleDataSubmit} />;
      case AppScreen.PROCESSING:
        return <Processing />;
      case AppScreen.RESULTS:
        return prediction && inputData ? (
          <ResultDashboard 
            prediction={prediction} 
            data={inputData} 
            onNext={() => setCurrentScreen(AppScreen.RECOMMENDATIONS)} 
          />
        ) : null;
      case AppScreen.RECOMMENDATIONS:
        return prediction ? (
          <Recommendations 
            status={prediction.status} 
            onNext={() => setCurrentScreen(AppScreen.ABOUT)}
          />
        ) : null;
      case AppScreen.ABOUT:
        return <About onRestart={reset} />;
      default:
        return <Home onStart={handleStart} onViewHow={handleViewImpact} />;
    }
  };

  return (
    <Layout currentScreen={currentScreen} onNavigate={(s) => setCurrentScreen(s)}>
      {renderScreen()}
    </Layout>
  );
};

export default App;

